import math

def solve(gender, weight_kg, height_cm, age_years):
    # Step 1: Calculate REE using gender-specific Harris-Benedict equation with resting state coefficient
    # Determine the appropriate formula based on gender
    if gender == "male":
        # Male formula: (66 + (13.7 * weight) + (5 * height) - (6.8 * age)) * 1.1
        base_ree = 66 + (13.7 * weight_kg) + (5 * height_cm) - (6.8 * age_years)
    elif gender == "female":
        # Female formula: (655 + (9.6 * weight) + (1.7 * height) - (4.7 * age)) * 1.1
        base_ree = 655 + (9.6 * weight_kg) + (1.7 * height_cm) - (4.7 * age_years)
    else:
        raise ValueError("Invalid gender: must be 'male' or 'female'")

    # Apply resting state coefficient of 1.1
    ree = base_ree * 1.1

    # Yield the result of this step
    yield {
        "step_name": "ree_calculation_by_gender",
        "step_description": "Calculate REE using gender-specific Harris-Benedict equation with resting state coefficient. If male: (66 + 13.7*weight + 5*height - 6.8*age) * 1.1; if female: (655 + 9.6*weight + 1.7*height - 4.7*age) * 1.1",
        "step_result": round(ree, 2),
        "unit": "kcal/day"
    }

    # Final output
    return round(ree, 2)
